		var arrFILTER;
var arrMARK;

function mark()
{
NomadTimeout("internal_load_mark();",100,"Marcando en la Lista..."); 
}

//Marca en la lista los legajos filtrados     
function internal_load_mark()
{
var auxArr;
auxArr = exec_qry();
if (auxArr==null) return;

arrMARK = auxArr; 

for (n=0; n<arrMARK.length; n++)
{    
var X=arrMARK[n];
for(i=0; i<arrFILTER.length; i++)
{            
	if(arrFILTER[i]==X) 
	{
		if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",X)==null) Ctrl("arrcheckFILTER").AddRow().SetAttr("ID",X);                                       
	  break;
	}
} 
} 
refreshList();
}

//Generar la lista de Legajos
function WhereLegajos()
{                      
var listLegajos,Where,t,subTxt,aux0,aux1;

 	Where="";

listLegajos=Ctrl('listlegajos').GetXValue();
if (listLegajos!="")
{
listLegajos=Replace(listLegajos,",",";").split(";");

for (t=0; t<listLegajos.length; t++)
{ 
	if (listLegajos[t].indexOf("-")>=0)
	{  
		subTxt=listLegajos[t].split("-");
		aux0=parseInt(subTxt[0],10);
		aux1=parseInt(subTxt[1],10);

     		if ((!isNaN(aux0)) || (!isNaN(aux1)))
     		{
     		if (Where!="") Where+=" OR ";
			Where+="(";
				if (!isNaN(aux0)) Where+="LEG.e_numero_legajo >= "+aux0;
				if ((!isNaN(aux0)) && (!isNaN(aux1))) Where+=" AND ";
				if (!isNaN(aux1)) Where+="LEG.e_numero_legajo <= "+aux1;
			Where+=")";
		}
	} else
	{                           
		aux0=parseInt(listLegajos[t],10);
		if (!isNaN(aux0)) 
		{
			if (Where!="") Where+=" OR ";
			Where+="LEG.e_numero_legajo="+aux0;
		}
	}
}
}

if (Where=="" && Ctrl('listlegajos').GetXValue()!="") Where="1=2";
Ctrl("leg_where").SetXValue(Where);
}

//Ejecuta el Query Seleccionado y devuelve un ARRAY con el resultado
function exec_qry()
{
	var np, nSQL, i;

	np = GetProxy();
	nSQL = np.SQLService(); 	
	var qry = Ctrl("main").getResource("qry_" + Ctrl("tab_filtro").GetSelectedPanelID());	
	var qryMembers = qry.split("##");
	var qryMembers = qryMembers[1].split(",");         

	var nmdDATA=new NomadXML("PARAM");
	for (i=0; i<qryMembers.length; i++)
	{     
		if(Ctrl(qryMembers[i]) != undefined )
		{
		    if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
			{
				alert("El valor es requerido");
				Ctrl(qryMembers[i]).SetFocus();
				return null;
			}				
			nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
		} 	
	}

	var result = nSQL.GetXML(qry, nmdDATA.ToString());
	var resultArray = XML2array(result);

	if(Ctrl("periodo").GetXValue()!="")
	{
	  // Ejecuta query EXTERNO
		if (Ctrl("main").getResource("qry_externo_per"))
		{
			qry = Ctrl("main").getResource("qry_externo_per");
			qryMembers = qry.split("##");
			qryMembers = qryMembers[1].split(",");         

		 	nmdDATA=new NomadXML("PARAM");
			for (i=0; i<qryMembers.length; i++)
			{			
				nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
			}

		 	result = nSQL.GetXML(qry, nmdDATA.ToString());
		  var auxResult = XML2array(result);

		  intersect(resultArray, auxResult);
		}
		return resultArray;
	}
	else
	{
		// Ejecuta query EXTERNO
		if (Ctrl("main").getResource("qry_externo_liq"))
		{
			qry = Ctrl("main").getResource("qry_externo_liq");
			qryMembers = qry.split("##");
			qryMembers = qryMembers[1].split(",");         

		 	nmdDATA=new NomadXML("PARAM");
			for (i=0; i<qryMembers.length; i++)
			{
				nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
			}

		 	result = nSQL.GetXML(qry, nmdDATA.ToString());
		  var auxResult = XML2array(result);

		  intersect(resultArray, auxResult);
		}

		return resultArray;
	}

}

//Agrega al Array A los elementos del Array B
function union(arrayA, arrayB)
{                    
var t;
var tmp=new Array();

//Creo la HASH
for (t=0; t<arrayA.length; t++) 
tmp["K"+arrayA[t]]=1;

//Agrego los que no estan	
for (t=0; t<arrayB.length; t++) 
if (tmp["K"+arrayB[t]]?false:true)
	arrayA.push(arrayB[t]);
}


//Elimina del Array A los elementos del Array B
function remove(arrayA, arrayB)
{
var t;
var tmp1=new Array();
var tmp2=new Array();

//Creo la HASH
for (t=0; t<arrayB.length; t++) 
tmp1["K"+arrayB[t]]=1;
for (t=0; t<arrayA.length; t++) 
tmp2.push(arrayA[t]);

//Limpio el array
arrayA.length=0;

//Agrego los elemento NO comunes
for (t=0; t<tmp2.length; t++)      
if (tmp1["K"+tmp2[t]]?false:true)
	arrayA.push(tmp2[t]);
} 


//Elimina del Array A los elementos que no estan en el Array B
function intersect(arrayA, arrayB)
{
var t;
var tmp1=new Array();
var tmp2=new Array();   

//Creo la HASH
for (t=0; t<arrayB.length; t++) 
tmp1["K"+arrayB[t]]=1;
for (t=0; t<arrayA.length; t++) 
tmp2.push(arrayA[t]);

//Limpio el array
arrayA.length=0;

//Agrego los elemento NO comunes
for (t=0; t<tmp2.length; t++)      
if (tmp1["K"+tmp2[t]]?true:false)
	arrayA.push(tmp2[t]);
}


//Elimina del Array A los elementos que no estan en el Array B
function copiar(arrayA, arrayB)
{
//Limpio el array
arrayA.length=0;

//Agrego los elemento NO comunes
for (var t=0; t<arrayB.length; t++)      
	arrayA.push(arrayB[t]);
}

//Transaforma un XML(tipo STRING) en ARRAY
function XML2array(xml)
{
var arr = new Array();                        
for (var cur=xml.FirstChild(); cur!=null; cur=cur.Next())
arr.push(cur.GetAttr("id"));
return arr;
}

