//Actualiza la lista con el nuevo ARRAY
function refreshList()
{              
 	var page=Ctrl("listFILTER").Page;
Ctrl("listFILTER").IDs=arrFILTER;
Ctrl("listFILTER").ResetSQL();
Ctrl("listFILTER").GotoPage(page);

Ctrl("filtrados").SetXValue("Legajos Filtrados: "+arrFILTER.length);
enable_buttons();
}

function load()    { NomadTimeout("internal_load();",100,"Cargando la Lista..."); }
function filter()  { NomadTimeout("internal_filter();",100,"Filtrando la Lista..."); }
function loadadd() { NomadTimeout("internal_loadadd();",100,"Agregando en la Lista..."); }        
function find()    { NomadTimeout("internal_find();",100,"Buscando en la lista..."); }        

function internal_load()
{  
  var auxArr;
auxArr = exec_qry();
if (auxArr==null) return;

arrFILTER = auxArr; 
refreshList();
}

function internal_filter()
{
  var auxArr;
auxArr = exec_qry();
if (auxArr==null) return;  

intersect(arrFILTER, auxArr);	
refreshList();
}

function internal_loadadd()
{
  var auxArr;
auxArr = exec_qry();
if (auxArr==null) return;  

union(arrFILTER, auxArr);	
refreshList();
}

function internal_find()
{ 
  var auxArr;
auxArr = exec_qry();
if (auxArr==null) return;  

//Obtiene los Elementos en Comun.
intersect(auxArr, arrFILTER);	
if (auxArr.length==0) 
{
alert("No se encontro ningun registro.");
return;
}

Ctrl("listFILTER").SetXValue(auxArr[0]);
}

function ONLOAD()
{
	var t, ROW, VALUES;
	arrFILTER = new Array();

	//Valores Iniciales
	for (t=0; t<Ctrl("arrFILTER").CountRow(); t++)
	{
	ROW=Ctrl("arrFILTER").GetRow(t);
	VALUES=ROW.GetAttr("VALUES").split(",");
	for (d=0; d<VALUES.length; d++)
		if (VALUES[d]!="")
			arrFILTER.push(VALUES[d]);
	}

 	//Actualizo la Lista
	refreshList();       

	//Llamo el Custom
	ONLOAD_custom();

	habilitarAfiliado();      

	//habilitarConfidenciales();

	if(!Ctrl('img_ojo').GetEnabled())
		Ctrl('l_confidencial').SetXValue('0');   
	else
		Ctrl('l_confidencial').SetXValue('1');

}

function habilitarConfidenciales()
{    

    var	np = GetProxy();
	var nSQL = np.SQLService(); 	
	var qry = Ctrl("main").getResource("qry_confidenciales");	 


	var result = nSQL.GetXML(qry, "<DATA oi_user='"+np.Etty()+"'/>");

    var confidencial = result.GetAttr("confidencial");

    if(confidencial == "noconf")
    {
	    Ctrl('cb_confidenciales').SetXValue('NC');
	    Ctrl('cb_confidenciales').SetEnabled(false);
    } 

}      

