//Elimino iten del FILTRO
function delFILTER()
{                      
for (var X=0; X<arrFILTER.length; X++)
{
if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",arrFILTER[X])!=null)
{                        
	arrFILTER.splice(X,1);
	X--;
}
}

Ctrl("listFILTER").SetXValue("");
 	Ctrl("arrcheckFILTER").DelAllRow();
refreshList();
}

//Limpio la Lista del FILTRO
function clearFILTER()
{  
for (var X=0; X<arrFILTER.length; X++)
{
if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",arrFILTER[X])==null)
{                        
	arrFILTER.splice(X,1);
	X--;
}
}

Ctrl("listFILTER").SetXValue("");
 	Ctrl("arrcheckFILTER").DelAllRow();
refreshList();
}                 

function checkFILTER()
{    
var X=Ctrl("listFILTER").GetXValue();
if (X!="" && Ctrl("listFILTER").LastColumnClick!="SEL")
{                                                  
if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",X)==null) Ctrl("arrcheckFILTER").AddRow().SetAttr("ID",X);
                                                  else Ctrl("arrcheckFILTER").DelRowByAttr("ID",X);    

Ctrl("listFILTER").SetXValue("");
refreshList();
} else           
enable_buttons();
}

